namespace Warehouse;

public sealed class InventoryTracker
{
    private readonly Dictionary<string, Dictionary<string, int>> _warehouseStock = new();
    private readonly Dictionary<string, int> _reorderThresholds = new();
    private const string DefaultWarehouse = "default";

    // --- Stock levels ---

    public int GetStockLevel(string sku)
    {
        ArgumentException.ThrowIfNullOrWhiteSpace(sku);
        return _warehouseStock.Values
            .Sum(w => w.TryGetValue(sku, out var qty) ? qty : 0);
    }

    public int GetStockLevel(string sku, string warehouse)
    {
        ArgumentException.ThrowIfNullOrWhiteSpace(sku);
        ArgumentException.ThrowIfNullOrWhiteSpace(warehouse);
        return _warehouseStock.TryGetValue(warehouse, out var stock)
            && stock.TryGetValue(sku, out var qty)
            ? qty
            : 0;
    }

    public void AddStock(string sku, int quantity) =>
        AddStock(sku, quantity, DefaultWarehouse);

    public void AddStock(string sku, int quantity, string warehouse)
    {
        ArgumentException.ThrowIfNullOrWhiteSpace(sku);
        if (quantity <= 0)
            throw new ArgumentOutOfRangeException(nameof(quantity), "Quantity must be positive.");
        ArgumentException.ThrowIfNullOrWhiteSpace(warehouse);

        if (!_warehouseStock.TryGetValue(warehouse, out var stock))
        {
            stock = new Dictionary<string, int>();
            _warehouseStock[warehouse] = stock;
        }

        stock.TryGetValue(sku, out var current);
        stock[sku] = current + quantity;
    }

    public void RemoveStock(string sku, int quantity) =>
        RemoveStock(sku, quantity, DefaultWarehouse);

    public void RemoveStock(string sku, int quantity, string warehouse)
    {
        ArgumentException.ThrowIfNullOrWhiteSpace(sku);
        if (quantity <= 0)
            throw new ArgumentOutOfRangeException(nameof(quantity), "Quantity must be positive.");
        ArgumentException.ThrowIfNullOrWhiteSpace(warehouse);

        if (!_warehouseStock.TryGetValue(warehouse, out var stock)
            || !stock.TryGetValue(sku, out var current)
            || current < quantity)
        {
            throw new InvalidOperationException("Insufficient stock.");
        }

        stock[sku] = current - quantity;
    }

    // --- Reorder alerts ---

    public void SetReorderThreshold(string sku, int threshold)
    {
        ArgumentException.ThrowIfNullOrWhiteSpace(sku);
        if (threshold < 0)
            throw new ArgumentOutOfRangeException(nameof(threshold), "Threshold must be non-negative.");
        _reorderThresholds[sku] = threshold;
    }

    public bool NeedsReorder(string sku)
    {
        ArgumentException.ThrowIfNullOrWhiteSpace(sku);
        if (!_reorderThresholds.TryGetValue(sku, out var threshold))
            return false;
        return GetStockLevel(sku) <= threshold;
    }

    // --- Warehouse transfers ---

    public void TransferStock(string sku, int quantity, string fromWarehouse, string toWarehouse)
    {
        ArgumentException.ThrowIfNullOrWhiteSpace(sku);
        if (quantity <= 0)
            throw new ArgumentOutOfRangeException(nameof(quantity), "Quantity must be positive.");
        ArgumentException.ThrowIfNullOrWhiteSpace(fromWarehouse);
        ArgumentException.ThrowIfNullOrWhiteSpace(toWarehouse);
        if (fromWarehouse == toWarehouse)
            throw new ArgumentException("Source and destination warehouse must differ.", nameof(toWarehouse));

        RemoveStock(sku, quantity, fromWarehouse);
        AddStock(sku, quantity, toWarehouse);
    }
}

using Warehouse;

namespace Warehouse.Tests;

[TestClass]
public sealed class StockLevelTests
{
    private InventoryTracker _tracker = null!;

    [TestInitialize]
    public void Setup() => _tracker = new InventoryTracker();

    // --- GetStockLevel ---

    [TestMethod]
    public void GetStockLevel_UnknownSku_ReturnsZero()
    {
        Assert.AreEqual(0, _tracker.GetStockLevel("UNKNOWN"));
    }

    [TestMethod]
    public void GetStockLevel_AfterAdd_ReturnsCorrectQuantity()
    {
        _tracker.AddStock("SKU-A", 25);
        Assert.AreEqual(25, _tracker.GetStockLevel("SKU-A"));
    }

    [TestMethod]
    public void GetStockLevel_AggregatesAcrossWarehouses()
    {
        _tracker.AddStock("SKU-A", 10, "WH-1");
        _tracker.AddStock("SKU-A", 30, "WH-2");
        Assert.AreEqual(40, _tracker.GetStockLevel("SKU-A"));
    }

    [TestMethod]
    public void GetStockLevel_ByWarehouse_ReturnsWarehouseOnly()
    {
        _tracker.AddStock("SKU-A", 10, "WH-1");
        _tracker.AddStock("SKU-A", 30, "WH-2");
        Assert.AreEqual(10, _tracker.GetStockLevel("SKU-A", "WH-1"));
    }

    [TestMethod]
    public void GetStockLevel_ByWarehouse_UnknownWarehouse_ReturnsZero()
    {
        _tracker.AddStock("SKU-A", 5, "WH-1");
        Assert.AreEqual(0, _tracker.GetStockLevel("SKU-A", "WH-MISSING"));
    }

    [TestMethod]
    [DataRow(null)]
    [DataRow("")]
    [DataRow("   ")]
    public void GetStockLevel_InvalidSku_Throws(string? sku)
    {
        Assert.ThrowsException<ArgumentException>(() => _tracker.GetStockLevel(sku!));
    }

    [TestMethod]
    [DataRow(null)]
    [DataRow("")]
    [DataRow("   ")]
    public void GetStockLevel_ByWarehouse_InvalidWarehouse_Throws(string? warehouse)
    {
        Assert.ThrowsException<ArgumentException>(
            () => _tracker.GetStockLevel("SKU-A", warehouse!));
    }

    // --- AddStock ---

    [TestMethod]
    public void AddStock_MultipleAdds_Accumulates()
    {
        _tracker.AddStock("SKU-A", 10);
        _tracker.AddStock("SKU-A", 15);
        Assert.AreEqual(25, _tracker.GetStockLevel("SKU-A"));
    }

    [TestMethod]
    public void AddStock_DifferentSkus_TrackedSeparately()
    {
        _tracker.AddStock("SKU-A", 10);
        _tracker.AddStock("SKU-B", 20);
        Assert.AreEqual(10, _tracker.GetStockLevel("SKU-A"));
        Assert.AreEqual(20, _tracker.GetStockLevel("SKU-B"));
    }

    [TestMethod]
    [DataRow(0)]
    [DataRow(-1)]
    [DataRow(-100)]
    public void AddStock_NonPositiveQuantity_Throws(int quantity)
    {
        Assert.ThrowsException<ArgumentOutOfRangeException>(
            () => _tracker.AddStock("SKU-A", quantity));
    }

    [TestMethod]
    [DataRow(null)]
    [DataRow("")]
    [DataRow("   ")]
    public void AddStock_InvalidSku_Throws(string? sku)
    {
        Assert.ThrowsException<ArgumentException>(
            () => _tracker.AddStock(sku!, 5));
    }

    [TestMethod]
    [DataRow(null)]
    [DataRow("")]
    [DataRow("   ")]
    public void AddStock_InvalidWarehouse_Throws(string? warehouse)
    {
        Assert.ThrowsException<ArgumentException>(
            () => _tracker.AddStock("SKU-A", 5, warehouse!));
    }

    // --- RemoveStock ---

    [TestMethod]
    public void RemoveStock_ReducesLevel()
    {
        _tracker.AddStock("SKU-A", 20);
        _tracker.RemoveStock("SKU-A", 8);
        Assert.AreEqual(12, _tracker.GetStockLevel("SKU-A"));
    }

    [TestMethod]
    public void RemoveStock_ExactAmount_LeavesZero()
    {
        _tracker.AddStock("SKU-A", 10);
        _tracker.RemoveStock("SKU-A", 10);
        Assert.AreEqual(0, _tracker.GetStockLevel("SKU-A"));
    }

    [TestMethod]
    public void RemoveStock_InsufficientStock_Throws()
    {
        _tracker.AddStock("SKU-A", 5);
        Assert.ThrowsException<InvalidOperationException>(
            () => _tracker.RemoveStock("SKU-A", 6));
    }

    [TestMethod]
    public void RemoveStock_NoStock_Throws()
    {
        Assert.ThrowsException<InvalidOperationException>(
            () => _tracker.RemoveStock("SKU-A", 1));
    }

    [TestMethod]
    public void RemoveStock_FromSpecificWarehouse()
    {
        _tracker.AddStock("SKU-A", 20, "WH-1");
        _tracker.AddStock("SKU-A", 10, "WH-2");
        _tracker.RemoveStock("SKU-A", 5, "WH-1");

        Assert.AreEqual(15, _tracker.GetStockLevel("SKU-A", "WH-1"));
        Assert.AreEqual(10, _tracker.GetStockLevel("SKU-A", "WH-2"));
    }

    [TestMethod]
    [DataRow(0)]
    [DataRow(-1)]
    public void RemoveStock_NonPositiveQuantity_Throws(int quantity)
    {
        _tracker.AddStock("SKU-A", 10);
        Assert.ThrowsException<ArgumentOutOfRangeException>(
            () => _tracker.RemoveStock("SKU-A", quantity));
    }

    [TestMethod]
    [DataRow(null)]
    [DataRow("")]
    public void RemoveStock_InvalidSku_Throws(string? sku)
    {
        Assert.ThrowsException<ArgumentException>(
            () => _tracker.RemoveStock(sku!, 1));
    }
}

[TestClass]
public sealed class ReorderAlertTests
{
    private InventoryTracker _tracker = null!;

    [TestInitialize]
    public void Setup() => _tracker = new InventoryTracker();

    [TestMethod]
    public void NeedsReorder_NoThresholdSet_ReturnsFalse()
    {
        _tracker.AddStock("SKU-A", 1);
        Assert.IsFalse(_tracker.NeedsReorder("SKU-A"));
    }

    [TestMethod]
    public void NeedsReorder_StockAboveThreshold_ReturnsFalse()
    {
        _tracker.SetReorderThreshold("SKU-A", 10);
        _tracker.AddStock("SKU-A", 50);
        Assert.IsFalse(_tracker.NeedsReorder("SKU-A"));
    }

    [TestMethod]
    public void NeedsReorder_StockAtThreshold_ReturnsTrue()
    {
        _tracker.SetReorderThreshold("SKU-A", 10);
        _tracker.AddStock("SKU-A", 10);
        Assert.IsTrue(_tracker.NeedsReorder("SKU-A"));
    }

    [TestMethod]
    public void NeedsReorder_StockBelowThreshold_ReturnsTrue()
    {
        _tracker.SetReorderThreshold("SKU-A", 10);
        _tracker.AddStock("SKU-A", 3);
        Assert.IsTrue(_tracker.NeedsReorder("SKU-A"));
    }

    [TestMethod]
    public void NeedsReorder_ZeroStock_WithThreshold_ReturnsTrue()
    {
        _tracker.SetReorderThreshold("SKU-A", 5);
        Assert.IsTrue(_tracker.NeedsReorder("SKU-A"));
    }

    [TestMethod]
    public void NeedsReorder_ThresholdZero_ZeroStock_ReturnsTrue()
    {
        _tracker.SetReorderThreshold("SKU-A", 0);
        Assert.IsTrue(_tracker.NeedsReorder("SKU-A"));
    }

    [TestMethod]
    public void NeedsReorder_ThresholdZero_HasStock_ReturnsFalse()
    {
        _tracker.SetReorderThreshold("SKU-A", 0);
        _tracker.AddStock("SKU-A", 1);
        Assert.IsFalse(_tracker.NeedsReorder("SKU-A"));
    }

    [TestMethod]
    public void NeedsReorder_ConsidersAllWarehouses()
    {
        _tracker.SetReorderThreshold("SKU-A", 15);
        _tracker.AddStock("SKU-A", 10, "WH-1");
        _tracker.AddStock("SKU-A", 10, "WH-2");
        // Total = 20, threshold = 15 → no reorder
        Assert.IsFalse(_tracker.NeedsReorder("SKU-A"));
    }

    [TestMethod]
    public void NeedsReorder_AfterRemoval_TriggersReorder()
    {
        _tracker.SetReorderThreshold("SKU-A", 10);
        _tracker.AddStock("SKU-A", 20);
        Assert.IsFalse(_tracker.NeedsReorder("SKU-A"));

        _tracker.RemoveStock("SKU-A", 15);
        Assert.IsTrue(_tracker.NeedsReorder("SKU-A"));
    }

    [TestMethod]
    public void SetReorderThreshold_CanBeUpdated()
    {
        _tracker.SetReorderThreshold("SKU-A", 10);
        _tracker.AddStock("SKU-A", 8);
        Assert.IsTrue(_tracker.NeedsReorder("SKU-A"));

        _tracker.SetReorderThreshold("SKU-A", 5);
        Assert.IsFalse(_tracker.NeedsReorder("SKU-A"));
    }

    [TestMethod]
    public void SetReorderThreshold_NegativeThreshold_Throws()
    {
        Assert.ThrowsException<ArgumentOutOfRangeException>(
            () => _tracker.SetReorderThreshold("SKU-A", -1));
    }

    [TestMethod]
    [DataRow(null)]
    [DataRow("")]
    public void SetReorderThreshold_InvalidSku_Throws(string? sku)
    {
        Assert.ThrowsException<ArgumentException>(
            () => _tracker.SetReorderThreshold(sku!, 10));
    }

    [TestMethod]
    [DataRow(null)]
    [DataRow("")]
    public void NeedsReorder_InvalidSku_Throws(string? sku)
    {
        Assert.ThrowsException<ArgumentException>(
            () => _tracker.NeedsReorder(sku!));
    }
}

[TestClass]
public sealed class WarehouseTransferTests
{
    private InventoryTracker _tracker = null!;

    [TestInitialize]
    public void Setup() => _tracker = new InventoryTracker();

    [TestMethod]
    public void TransferStock_MovesQuantityBetweenWarehouses()
    {
        _tracker.AddStock("SKU-A", 30, "WH-1");
        _tracker.TransferStock("SKU-A", 10, "WH-1", "WH-2");

        Assert.AreEqual(20, _tracker.GetStockLevel("SKU-A", "WH-1"));
        Assert.AreEqual(10, _tracker.GetStockLevel("SKU-A", "WH-2"));
    }

    [TestMethod]
    public void TransferStock_TotalStockUnchanged()
    {
        _tracker.AddStock("SKU-A", 50, "WH-1");
        _tracker.TransferStock("SKU-A", 20, "WH-1", "WH-2");

        Assert.AreEqual(50, _tracker.GetStockLevel("SKU-A"));
    }

    [TestMethod]
    public void TransferStock_EntireQuantity()
    {
        _tracker.AddStock("SKU-A", 10, "WH-1");
        _tracker.TransferStock("SKU-A", 10, "WH-1", "WH-2");

        Assert.AreEqual(0, _tracker.GetStockLevel("SKU-A", "WH-1"));
        Assert.AreEqual(10, _tracker.GetStockLevel("SKU-A", "WH-2"));
    }

    [TestMethod]
    public void TransferStock_InsufficientSource_Throws()
    {
        _tracker.AddStock("SKU-A", 5, "WH-1");
        Assert.ThrowsException<InvalidOperationException>(
            () => _tracker.TransferStock("SKU-A", 10, "WH-1", "WH-2"));
    }

    [TestMethod]
    public void TransferStock_InsufficientSource_DoesNotModifyDestination()
    {
        _tracker.AddStock("SKU-A", 5, "WH-1");
        _tracker.AddStock("SKU-A", 10, "WH-2");

        try { _tracker.TransferStock("SKU-A", 20, "WH-1", "WH-2"); }
        catch (InvalidOperationException) { }

        Assert.AreEqual(5, _tracker.GetStockLevel("SKU-A", "WH-1"));
        Assert.AreEqual(10, _tracker.GetStockLevel("SKU-A", "WH-2"));
    }

    [TestMethod]
    public void TransferStock_SameWarehouse_Throws()
    {
        _tracker.AddStock("SKU-A", 10, "WH-1");
        Assert.ThrowsException<ArgumentException>(
            () => _tracker.TransferStock("SKU-A", 5, "WH-1", "WH-1"));
    }

    [TestMethod]
    [DataRow(0)]
    [DataRow(-5)]
    public void TransferStock_NonPositiveQuantity_Throws(int quantity)
    {
        _tracker.AddStock("SKU-A", 10, "WH-1");
        Assert.ThrowsException<ArgumentOutOfRangeException>(
            () => _tracker.TransferStock("SKU-A", quantity, "WH-1", "WH-2"));
    }

    [TestMethod]
    [DataRow(null)]
    [DataRow("")]
    public void TransferStock_InvalidSku_Throws(string? sku)
    {
        Assert.ThrowsException<ArgumentException>(
            () => _tracker.TransferStock(sku!, 1, "WH-1", "WH-2"));
    }

    [TestMethod]
    [DataRow(null)]
    [DataRow("")]
    public void TransferStock_InvalidFromWarehouse_Throws(string? from)
    {
        Assert.ThrowsException<ArgumentException>(
            () => _tracker.TransferStock("SKU-A", 1, from!, "WH-2"));
    }

    [TestMethod]
    [DataRow(null)]
    [DataRow("")]
    public void TransferStock_InvalidToWarehouse_Throws(string? to)
    {
        Assert.ThrowsException<ArgumentException>(
            () => _tracker.TransferStock("SKU-A", 1, "WH-1", to!));
    }

    [TestMethod]
    public void TransferStock_TriggersReorderOnSource()
    {
        _tracker.SetReorderThreshold("SKU-A", 10);
        _tracker.AddStock("SKU-A", 20, "WH-1");
        Assert.IsFalse(_tracker.NeedsReorder("SKU-A"));

        _tracker.TransferStock("SKU-A", 15, "WH-1", "WH-2");
        // Total still 20, so no reorder
        Assert.IsFalse(_tracker.NeedsReorder("SKU-A"));
    }
}

